import React, { useState, useEffect, useRef } from 'react';
import { ProposalItem, StrategicMapItem, ProposalMetadata, SolutionItem, ProposalRecord, AppCustomization } from '../types';
import { generateStrategicMapping, improveObservationText, generateCommercialPresentationStream } from '../services/gemini';
import { SupabaseService } from '../services/api';

interface ProposalBuilderProps {
  appConfig: AppCustomization;
}

const PhantPattern = () => (
  <svg width="100%" height="100%" className="absolute inset-0 pointer-events-none opacity-[0.05]">
    <pattern id="phant-pattern" x="0" y="0" width="160" height="160" patternUnits="userSpaceOnUse">
      <image href="http://phant.com.br/uploads/simbolo_roxo.png" x="40" y="40" width="80" height="80" opacity="0.1" />
    </pattern>
    <rect width="100%" height="100%" fill="url(#phant-pattern)" />
  </svg>
);

const ProposalBuilder: React.FC<ProposalBuilderProps> = ({ appConfig }) => {
  const [proposalItems, setProposalItems] = useState<ProposalItem[]>([]);
  const [strategicMap, setStrategicMap] = useState<StrategicMapItem[]>([]);
  const [catalog, setCatalog] = useState<SolutionItem[]>([]);
  const [proposalHistory, setProposalHistory] = useState<ProposalRecord[]>([]);
  const [metadata, setMetadata] = useState<ProposalMetadata>({
    clientName: '',
    industry: '',
    website: '',
    instagram: '',
    meetingNotesPains: '',
    meetingNotesDesires: '',
    observations: '',
    date: new Date().toLocaleDateString('pt-BR'),
    consultant: 'Estrategista PhantLab',
    headline: 'PROPOSTA DE MOVIMENTO ESTRATÉGICO'
  });

  const [isGeneratingAI, setIsGeneratingAI] = useState(false);
  const [isGeneratingPresentation, setIsGeneratingPresentation] = useState(false);
  const [presentationHtml, setPresentationHtml] = useState<string | null>(null);
  const [exportStatus, setExportStatus] = useState<'idle' | 'saving' | 'ready' | 'error'>('idle');
  const [activeTab, setActiveTab] = useState<'info' | 'solutions' | 'mapping' | 'history'>('info');
  const [zoom, setZoom] = useState(0.45);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [validationError, setValidationError] = useState<string | null>(null);
  const previewRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem('phant_current_proposal');
    if (saved) setProposalItems(JSON.parse(saved));
    SupabaseService.fetchSolutions().then(data => setCatalog(data || []));
    loadHistory();
  }, []);

  const loadHistory = async () => {
    const history = await SupabaseService.fetchProposalsHistory();
    setProposalHistory(history || []);
  };

  const total = proposalItems.reduce((acc, curr) => acc + curr.totalPrice, 0);
  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const handleGenerateAI = async () => {
    if (!metadata.clientName) { setValidationError("Nome do cliente obrigatório"); return; }
    setIsGeneratingAI(true);
    try {
      const mapping = await generateStrategicMapping(metadata);
      setStrategicMap(mapping || []);
      setActiveTab('mapping');
    } finally { setIsGeneratingAI(false); }
  };

  const handleGeneratePresentation = async () => {
    if (!metadata.clientName || proposalItems.length === 0) return;
    setPresentationHtml("");
    setIsGeneratingPresentation(true);
    try {
      await generateCommercialPresentationStream(metadata, proposalItems, strategicMap, setPresentationHtml);
    } finally { setIsGeneratingPresentation(false); }
  };

  const handleExport = async () => {
    if (!metadata.clientName) { setValidationError("Defina o cliente"); return; }
    setExportStatus('saving');
    try {
      await SupabaseService.saveProposal(metadata.clientName, metadata.industry || "N/A", total, metadata.consultant, proposalItems, metadata);
      setExportStatus('ready');
      setTimeout(() => { window.print(); setExportStatus('idle'); }, 1000);
    } catch { setExportStatus('error'); }
  };

  const adjustZoom = (delta: number) => setZoom(prev => Math.min(Math.max(prev + delta, 0.2), 2));
  const toggleFullscreen = () => {
    if (!document.fullscreenElement) { previewRef.current?.requestFullscreen(); setIsFullscreen(true); } 
    else { document.exitFullscreen(); setIsFullscreen(false); }
  };

  return (
    <div className={`flex flex-col lg:flex-row gap-8 animate-in fade-in duration-700 ${isFullscreen ? 'fixed inset-0 z-[100] bg-[#1a1a1a]' : ''}`}>

      {!isFullscreen && (
        <div className="w-full lg:w-[450px] space-y-8 no-print shrink-0">
          <header className="space-y-2">
            <h2 className="text-4xl font-black text-gray-900 tracking-tighter">Gerador.</h2>
            <p className="text-gray-400 text-sm font-medium">Configure a identidade da proposta.</p>
          </header>

          <div className="bg-white rounded-[40px] border border-gray-100 shadow-xl overflow-hidden flex flex-col h-[750px] relative">
            <nav className="flex p-4 gap-2 bg-gray-50 border-b border-gray-100 no-print">
              {(['info', 'solutions', 'mapping', 'history'] as const).map(t => (
                <button key={t} onClick={() => setActiveTab(t)} className={`flex-1 py-3 rounded-2xl text-[9px] font-black uppercase tracking-widest transition-all ${activeTab === t ? 'bg-brand text-white shadow-lg shadow-brand/20' : 'text-gray-400 hover:text-brand'}`}>
                  {t === 'info' ? 'Dados' : t === 'solutions' ? 'Itens' : t === 'mapping' ? 'Estratégia' : 'Histórico'}
                </button>
              ))}
            </nav>

            <div className="flex-1 overflow-y-auto p-8 space-y-8 custom-scrollbar no-print">
              {activeTab === 'info' && (
                <div className="space-y-6 animate-in slide-in-from-left-4 duration-300">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-300 uppercase tracking-widest ml-2">Empresa do Cliente</label>
                    <input value={metadata.clientName} onChange={e => setMetadata({...metadata, clientName: e.target.value.toUpperCase()})} className="w-full bg-gray-50 p-4 rounded-2xl font-black text-sm outline-none focus:border-brand border border-transparent" placeholder="RAZÃO SOCIAL" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-300 uppercase tracking-widest ml-2">Setor de Atuação</label>
                    <input value={metadata.industry} onChange={e => setMetadata({...metadata, industry: e.target.value})} className="w-full bg-gray-50 p-4 rounded-2xl font-bold text-xs outline-none" placeholder="Ex: Tecnologia, Varejo..." />
                  </div>
                  <button onClick={handleGenerateAI} disabled={isGeneratingAI} className="w-full py-5 bg-black text-white rounded-[30px] font-black text-[10px] uppercase tracking-widest hover:bg-brand transition-all shadow-xl disabled:opacity-50">
                    {isGeneratingAI ? 'PESQUISANDO...' : '✨ ANALISAR EMPRESA COM IA'}
                  </button>
                </div>
              )}

              {activeTab === 'solutions' && (
                <div className="space-y-4 animate-in slide-in-from-left-4 duration-300">
                   {proposalItems.map(item => (
                      <div key={item.instanceId} className="p-4 bg-gray-50 rounded-2xl flex justify-between items-center group">
                        <div>
                          <p className="font-black text-[11px] uppercase tracking-tight">{item.name}</p>
                          <p className="text-[9px] text-brand font-extrabold">{formatCurrency(item.totalPrice)}</p>
                        </div>
                        <button onClick={() => setProposalItems(prev => prev.filter(p => p.instanceId !== item.instanceId))} className="text-gray-300 hover:text-red-500"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12"/></svg></button>
                      </div>
                    ))}
                    <div className="pt-4 border-t border-gray-100">
                       <p className="text-[9px] font-black text-gray-300 uppercase tracking-widest mb-4">Adicionar Manual</p>
                       <div className="space-y-2">
                          {catalog.slice(0, 5).map(sol => (
                            <button key={sol.id} onClick={() => setProposalItems(prev => [...prev, { instanceId: `m-${Date.now()}`, solutionId: sol.id, name: sol.solucao, basePrice: sol.valor_base_num, selectedOptions: [], totalPrice: sol.valor_base_num, duration: sol.duracao }])} className="w-full text-left p-3 rounded-xl border border-gray-100 text-[10px] font-bold text-gray-400 hover:border-brand hover:text-brand transition-all">+ {sol.solucao}</button>
                          ))}
                       </div>
                    </div>
                </div>
              )}

              {activeTab === 'mapping' && (
                <div className="space-y-4 animate-in slide-in-from-left-4 duration-300">
                   {strategicMap.map((m, i) => (
                    <div key={i} className="p-5 bg-brand/5 border border-brand/10 rounded-3xl space-y-3">
                        <textarea value={m.current} onChange={e => { const n = [...strategicMap]; n[i].current = e.target.value; setStrategicMap(n); }} className="w-full bg-transparent border-none p-0 text-[10px] font-medium text-gray-400 resize-none focus:ring-0" />
                        <div className="h-px bg-brand/10 w-full"></div>
                        <textarea value={m.desired} onChange={e => { const n = [...strategicMap]; n[i].desired = e.target.value; setStrategicMap(n); }} className="w-full bg-transparent border-none p-0 text-[11px] font-black text-gray-900 resize-none focus:ring-0" />
                    </div>
                  ))}
                </div>
              )}

              {activeTab === 'history' && (
                <div className="space-y-3">
                  {proposalHistory.map(record => (
                    <div key={record.id} className="p-4 bg-gray-50 rounded-2xl border border-transparent hover:border-brand cursor-pointer transition-all" onClick={() => { setProposalItems(record.items); setMetadata(record.metadata); }}>
                       <p className="font-black text-[11px] text-gray-900">{record.client_name}</p>
                       <p className="text-[9px] font-bold text-brand mt-1">{formatCurrency(record.total_value)}</p>
                    </div>
                  ))}
                </div>
              )}
            </div>

            <div className="p-8 bg-black text-white space-y-6">
              <div className="flex justify-between items-end">
                  <span className="text-[10px] font-black text-white/30 uppercase tracking-widest">Total Estimado</span>
                  <span className="text-3xl font-black tracking-tighter">{formatCurrency(total)}</span>
              </div>
              <button onClick={handleExport} disabled={exportStatus !== 'idle'} className="w-full py-5 bg-brand text-white rounded-[24px] font-black text-[11px] uppercase tracking-[0.2em] shadow-xl hover:scale-105 transition-all disabled:opacity-50">
                {exportStatus === 'saving' ? 'SALVANDO...' : 'SALVAR E GERAR PDF'}
              </button>
              <button onClick={handleGeneratePresentation} disabled={isGeneratingPresentation} className="w-full py-4 bg-white/10 text-white rounded-[24px] font-black text-[10px] uppercase tracking-[0.2em] hover:bg-white/20 transition-all flex items-center justify-center gap-2">
                 {isGeneratingPresentation ? 'CRIANDO APRESENTAÇÃO...' : '🚀 GERAR APRESENTAÇÃO'}
              </button>
            </div>
          </div>
        </div>
      )}

      {presentationHtml && (
        <div className="fixed inset-0 z-[200] bg-black flex flex-col">
          <div className="p-6 flex justify-between items-center border-b border-white/10">
             <div className="flex items-center gap-4">
                <img src="http://phant.com.br/uploads/simbolo_lgtroxo.png" className="w-8 h-8" alt="Phant" />
                <h3 className="text-white font-black text-lg">Apresentação Gerada IA</h3>
             </div>
             <button onClick={() => setPresentationHtml(null)} className="p-2 bg-red-600 text-white rounded-lg"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M6 18L18 6M6 6l12 12"/></svg></button>
          </div>
          <iframe srcDoc={presentationHtml} className="flex-1 w-full border-none bg-white" title="Apresentação" />
        </div>
      )}

      <div className={`flex-1 relative flex flex-col items-center bg-[#151515] rounded-[60px] overflow-y-auto custom-scrollbar proposal-preview-area ${isFullscreen ? 'h-full w-full rounded-none' : 'p-12'}`}>
        <div className="sticky top-4 z-[50] no-print bg-white/10 backdrop-blur-xl border border-white/10 rounded-full p-2 flex items-center gap-2 mb-8 shadow-2xl">
          <button onClick={() => adjustZoom(-0.05)} className="w-10 h-10 flex items-center justify-center text-white hover:bg-white/10 rounded-full"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M20 12H4" strokeWidth="3" strokeLinecap="round"/></svg></button>
          <span className="text-[10px] font-black text-white/40 px-2">{Math.round(zoom * 100)}%</span>
          <button onClick={() => adjustZoom(0.05)} className="w-10 h-10 flex items-center justify-center text-white hover:bg-white/10 rounded-full"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="3" strokeLinecap="round"/></svg></button>
          <div className="w-px h-6 bg-white/10 mx-1"></div>
          <button onClick={toggleFullscreen} className="w-10 h-10 flex items-center justify-center text-white hover:bg-white/10 rounded-full"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M15 3h6m0 0v6m0-6L14 10M9 3H3m0 0v6m0-6l7 7M15 21h6m0 0v-6m0 6l-7-7M9 21H3m0 0v-6m0 6l7-7" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/></svg></button>
        </div>

        <div className="origin-top proposal-container flex flex-col items-center" style={{ transform: `scale(${zoom})` }}>
          {/* Capa PDF PhantLab */}
          <section className="printable-page w-[210mm] min-h-[297mm] bg-black text-white p-24 flex flex-col justify-between relative shadow-2xl shrink-0 mb-12 print:mb-0 print:shadow-none animate-in zoom-in-95 duration-500">
            <PhantPattern />
            <div className="relative z-10 flex justify-between items-start">
              <img src="http://phant.com.br/uploads/logo_light.png" className="h-10 object-contain" alt="PhantLab" />
              <div className="text-right">
                  <p className="text-[10px] font-black uppercase tracking-[0.4em] text-brand">Business Proposals</p>
                  <p className="font-bold text-sm mt-1">{metadata.consultant}</p>
              </div>
            </div>

            <div className="relative z-10 space-y-12">
              <div className="w-32 h-2 bg-brand mb-8"></div>
              <h1 className="text-8xl font-black tracking-tighter leading-[0.85] uppercase">
                  {metadata.headline?.split(' ').map((word, i) => <span key={i} className="block">{word}</span>)}
              </h1>
            </div>

            <div className="relative z-10 flex justify-between items-end border-t border-white/20 pt-12">
              <div className="space-y-2">
                  <p className="text-[11px] font-black uppercase tracking-[0.5em] text-white/40">Exclusivo para</p>
                  <p className="text-5xl font-black tracking-tighter">{metadata.clientName || 'CLIENTE'}</p>
              </div>
              <div className="text-right">
                  <p className="text-[11px] font-black uppercase tracking-widest text-white/40">Emissão</p>
                  <p className="font-bold text-lg">{metadata.date}</p>
              </div>
            </div>
          </section>

          {/* Página 02: Diagnóstico Estratégico */}
          <section className="printable-page w-[210mm] min-h-[297mm] bg-white text-black p-24 flex flex-col shrink-0 mb-12 print:mb-0 shadow-2xl">
             <header className="flex justify-between items-start border-b border-gray-100 pb-10 mb-16">
                <img src="http://phant.com.br/uploads/simbolo_roxo.png" className="w-12 h-12" alt="Phant" />
                <div className="text-right">
                   <p className="text-[10px] font-black uppercase tracking-widest text-gray-400">01. Diagnóstico</p>
                </div>
             </header>
             <h2 className="text-5xl font-black tracking-tighter mb-12">A Lei do Movimento</h2>
             <div className="grid grid-cols-1 gap-10">
                {strategicMap.map((map, i) => (
                  <div key={i} className="flex gap-10">
                    <div className="flex-1 p-10 bg-gray-50 rounded-[40px] relative overflow-hidden">
                       <span className="text-[9px] font-black text-red-500 uppercase tracking-widest block mb-4">Estado Atual</span>
                       <p className="text-sm font-medium text-gray-500 italic">"{map.current}"</p>
                    </div>
                    <div className="flex items-center text-brand">
                       <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M13 5l7 7-7 7M5 5l7 7-7 7"/></svg>
                    </div>
                    <div className="flex-1 p-10 bg-[#e9e5ff]/50 rounded-[40px] border border-[#e9e5ff] relative overflow-hidden">
                       <span className="text-[9px] font-black text-brand uppercase tracking-widest block mb-4">Estado PhantLab</span>
                       <p className="text-lg font-black tracking-tight text-gray-900 leading-tight">{map.desired}</p>
                    </div>
                  </div>
                ))}
             </div>
          </section>

          {/* Página 03: Investimento */}
          <section className="printable-page w-[210mm] min-h-[297mm] bg-white text-black p-24 flex flex-col shrink-0 mb-12 print:mb-0 shadow-2xl">
             <header className="flex justify-between items-start border-b border-gray-100 pb-10 mb-16">
                <img src="http://phant.com.br/uploads/logo_black.png" className="h-8 object-contain" alt="Phant" />
                <div className="text-right">
                   <p className="text-[10px] font-black uppercase tracking-widest text-gray-400">02. Investimento</p>
                </div>
             </header>
             <h2 className="text-5xl font-black tracking-tighter mb-12">Aceleração Mensal</h2>
             <div className="space-y-6">
                {proposalItems.map((item, i) => (
                  <div key={i} className="flex justify-between items-center p-8 border-b-2 border-gray-50 group hover:border-brand transition-all">
                     <div className="space-y-1">
                        <p className="font-black text-xl tracking-tight text-gray-900 uppercase">{item.name}</p>
                        <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{item.duration}</p>
                     </div>
                     <p className="text-2xl font-black tracking-tighter">{formatCurrency(item.totalPrice)}</p>
                  </div>
                ))}
                <div className="pt-12 flex flex-col items-end">
                   <p className="text-[11px] font-black uppercase tracking-[0.4em] text-brand mb-2">Total Consolidado</p>
                   <p className="text-6xl font-black tracking-tighter">{formatCurrency(total)}</p>
                </div>
             </div>
             <footer className="mt-auto pt-12 border-t border-gray-100 flex justify-between items-center">
                <p className="text-[10px] font-black text-gray-300 uppercase tracking-widest">© 2024 PhantLab Platform</p>
                <div className="flex gap-4">
                   <div className="w-8 h-8 bg-gray-900 rounded-lg"></div>
                   <div className="w-8 h-8 bg-brand rounded-lg"></div>
                </div>
             </footer>
          </section>
        </div>
      </div>
    </div>
  );
};

export default ProposalBuilder;
